import React, { useState, useEffect, useRef, useCallback } from 'react';

export default function RestTimer({ seconds, onDone, soundEnabled = true }) {
  // endTime 기반: 화면이 꺼져도 정확한 잔여 시간 계산
  const endTimeRef = useRef(Date.now() + seconds * 1000);
  const [remaining, setRemaining] = useState(seconds);
  const rafRef = useRef(null);
  const doneRef = useRef(false);
  const audioCtxRef = useRef(null);

  const playBeep = useCallback(() => {
    if (!soundEnabled) return;
    try {
      if (!audioCtxRef.current)
        audioCtxRef.current = new (window.AudioContext || window.webkitAudioContext)();
      const ctx = audioCtxRef.current;
      [0, 0.35, 0.7].forEach(offset => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain); gain.connect(ctx.destination);
        osc.frequency.value = 880;
        gain.gain.setValueAtTime(0.3, ctx.currentTime + offset);
        gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + offset + 0.3);
        osc.start(ctx.currentTime + offset);
        osc.stop(ctx.currentTime + offset + 0.3);
      });
    } catch {}
  }, [soundEnabled]);

  const tick = useCallback(() => {
    const left = Math.max(0, Math.round((endTimeRef.current - Date.now()) / 1000));
    setRemaining(left);
    if (left <= 0 && !doneRef.current) {
      doneRef.current = true;
      playBeep();
      if (navigator.vibrate) navigator.vibrate([200, 100, 200]);
      onDone();
      return;
    }
    rafRef.current = setTimeout(tick, 250);
  }, [onDone, playBeep]);

  useEffect(() => {
    rafRef.current = setTimeout(tick, 250);

    // Wake Lock - 휴식 중 화면 꺼짐 방지
    let wakeLock = null;
    (async () => {
      if ('wakeLock' in navigator) {
        try { wakeLock = await navigator.wakeLock.request('screen'); } catch {}
      }
    })();

    // 화면 복귀 시 즉시 업데이트
    const onVisible = () => {
      if (document.visibilityState === 'visible') tick();
    };
    document.addEventListener('visibilitychange', onVisible);

    return () => {
      clearTimeout(rafRef.current);
      document.removeEventListener('visibilitychange', onVisible);
      wakeLock?.release().catch(() => {});
    };
  }, [tick]);

  const mins = Math.floor(remaining / 60);
  const secs = remaining % 60;
  const display = `${mins}:${String(secs).padStart(2, '0')}`;

  return (
    <div className="timer-overlay">
      <div className="timer-label">휴식 중</div>
      <div className="timer-display">{display}</div>
      <button className="timer-skip" onClick={onDone}>건너뛰기</button>
    </div>
  );
}
