import React, { useState, useEffect, useCallback, useRef } from 'react';
import { SESSION_CONFIG, SESSION_ORDER, getNextSession } from '../data/workoutConfig';
import {
  getCurrentSession, setCurrentSession, saveSession,
  getLastSessionByKey, checkAndUpdatePR,
} from '../data/storage';
import { buildNewSession } from '../data/sessionBuilder';
import RestTimer from './RestTimer';
import RunningTimer from './RunningTimer';

const DEFAULT_SESSION = '1-1';

const SESSION_BANNER = {
  strength:    'Warm-up 20개 × 3세트  →  Workout 5개 × 5세트  →  Cool-down',
  bodybuilding:'Workout 12개 × 5세트',
  mixed:       '풀업 5세트 + 행잉레그레이즈 5세트 → 러닝 30분',
  running:     '러닝',
};

function formatDate(d) {
  const date = new Date(d);
  return `${date.getMonth() + 1}.${String(date.getDate()).padStart(2, '0')}`;
}
function formatDuration(s) {
  if (!s) return '-';
  const m = Math.floor(s / 60), sec = s % 60;
  return sec > 0 ? `${m}분 ${sec}초` : `${m}분`;
}

function getPrevSummary(sessionKey, exerciseName) {
  const prev = getLastSessionByKey(sessionKey);
  if (!prev) return null;
  const ex = prev.exercises?.find(e => e.name === exerciseName);
  if (!ex) return null;
  const mainSets = ex.sets.filter(s => s.set_type === 'main' && s.is_completed);
  if (!mainSets.length) return null;
  const first = mainSets[0];
  const wStr = first.target_weight ? `${first.target_weight}kg × ` : '';
  const dStr = ex.difficulty
    ? (ex.difficulty === 'high' ? ' · 상 💪' : ex.difficulty === 'mid' ? ' · 중 👊' : ' · 하 😌')
    : '';
  return `이전 ${prev.session_key} (${formatDate(prev.date)}) | 본세트 ${wStr}${first.actual_reps ?? first.target_reps}개${dStr}`;
}

// 세션 선택 모달
function SessionPicker({ current, onSelect, onClose }) {
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-sheet" onClick={e => e.stopPropagation()}>
        <div className="modal-handle" />
        <div style={{fontWeight:700, fontSize:17, marginBottom:14}}>운동 선택</div>
        <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:10}}>
          {SESSION_ORDER.map(key => {
            const cfg = SESSION_CONFIG[key];
            return (
              <button key={key}
                className={`session-pick-btn ${key === current ? 'active' : ''}`}
                onClick={() => { onSelect(key); onClose(); }}
              >
                <span className="session-pick-key">{key}</span>
                <span className="session-pick-name">{cfg.name}</span>
              </button>
            );
          })}
        </div>
        <button className="btn btn-ghost btn-full" style={{marginTop:16}} onClick={onClose}>닫기</button>
      </div>
    </div>
  );
}

export default function TodayTab() {
  const [sessionKey, setSessionKey]     = useState(() => getCurrentSession() || DEFAULT_SESSION);
  const [session, setSession]           = useState(null);
  const [timer, setTimer]               = useState(null);
  const [sessionDone, setSessionDone]   = useState(false);
  const [showPicker, setShowPicker]     = useState(false);
  const [workoutStartTime, setWorkoutStartTime] = useState(null);
  const [elapsed, setElapsed]           = useState(0);
  const [workoutRunning, setWorkoutRunning]     = useState(false);
  const elapsedRef = useRef(null);

  useEffect(() => {
    setSession(buildNewSession(sessionKey));
    setSessionDone(false);
    setWorkoutStartTime(null);
    setElapsed(0);
    setWorkoutRunning(false);
    setTimer(null);
  }, [sessionKey]);

  useEffect(() => {
    if (!workoutRunning) { clearInterval(elapsedRef.current); return; }
    elapsedRef.current = setInterval(() =>
      setElapsed(Math.floor((Date.now() - workoutStartTime) / 1000)), 1000);
    return () => clearInterval(elapsedRef.current);
  }, [workoutRunning, workoutStartTime]);

  function startWorkout() { setWorkoutStartTime(Date.now()); setWorkoutRunning(true); }
  function cancelWorkout() {
    clearInterval(elapsedRef.current);
    setWorkoutRunning(false); setWorkoutStartTime(null); setElapsed(0); setTimer(null);
  }
  function handlePickSession(key) { setCurrentSession(key); setSessionKey(key); }

  const setExDifficulty = useCallback((exIdx, value) => {
    setSession(prev => {
      const next = { ...prev, exercises: prev.exercises.map((ex, ei) =>
        ei !== exIdx ? ex : { ...ex, difficulty: value }) };
      saveSession(next); return next;
    });
  }, []);

  const updateSet = useCallback((exIdx, setIdx, field, value) => {
    setSession(prev => ({
      ...prev,
      exercises: prev.exercises.map((ex, ei) =>
        ei !== exIdx ? ex : {
          ...ex, sets: ex.sets.map((s, si) => si !== setIdx ? s : { ...s, [field]: value }),
        }
      ),
    }));
  }, []);

  const completeSet = useCallback((exIdx, setIdx) => {
    setSession(prev => {
      const next = { ...prev };
      next.exercises = prev.exercises.map((e, ei) => {
        if (ei !== exIdx) return e;
        const mainW = e.sets.filter(s => s.set_type === 'main')[0]?.target_weight ?? 0;
        return { ...e, sets: e.sets.map((s, si) => {
          if (si !== setIdx) return s;
          let w = s.target_weight;
          if (s.set_type === 'cooldown' && !w) w = Math.round(mainW * 0.5 / 2.5) * 2.5 || null;
          const reps = s.actual_reps ?? s.target_reps;
          let isPR = false;
          if (s.set_type === 'main' && (w ?? 0) > 0 && reps)
            isPR = checkAndUpdatePR(e.name, w, reps, next.date);
          return { ...s, is_completed: true, is_pr: isPR, target_weight: w };
        })};
      });
      saveSession(next);
      if (SESSION_CONFIG[next.session_key].restSeconds > 0)
        setTimer(SESSION_CONFIG[next.session_key].restSeconds);
      return next;
    });
  }, []);

  const completeAllSets = useCallback((exIdx) => {
    setSession(prev => {
      const next = { ...prev };
      next.exercises = prev.exercises.map((e, ei) => {
        if (ei !== exIdx) return e;
        const mainW = e.sets.filter(s => s.set_type === 'main')[0]?.target_weight ?? 0;
        return { ...e, sets: e.sets.map(s => {
          if (s.is_completed) return s;
          let w = s.target_weight;
          if (s.set_type === 'cooldown' && !w) w = Math.round(mainW * 0.5 / 2.5) * 2.5 || null;
          const reps = s.actual_reps ?? s.target_reps;
          let isPR = false;
          if (s.set_type === 'main' && (w ?? 0) > 0 && reps)
            isPR = checkAndUpdatePR(e.name, w, reps, next.date);
          return { ...s, is_completed: true, is_pr: isPR, target_weight: w };
        })};
      });
      saveSession(next); return next;
    });
  }, []);

  function forceCompleteSession() {
    if (!session) return;
    clearInterval(elapsedRef.current); setWorkoutRunning(false);
    const duration = workoutStartTime ? Math.floor((Date.now() - workoutStartTime) / 1000) : null;
    const done = { ...session, completed: true, workout_duration: duration };
    saveSession(done);
    setCurrentSession(getNextSession(sessionKey));
    setSessionDone(true); setTimer(null);
    setSession(s => ({ ...s, completed: true, workout_duration: duration }));
  }
  function startNextSession() { setSessionKey(getNextSession(sessionKey)); }

  if (!session) return <div className="page"><p>로딩 중...</p></div>;

  const config = SESSION_CONFIG[sessionKey];
  const bannerText = SESSION_BANNER[config.type] ?? '';

  const Header = () => (
    <div className="page-header">
      <div style={{display:'flex', alignItems:'center', gap:10}}>
        <div className="page-title">{sessionKey} {config.name}</div>
        {!sessionDone && (
          <button className="session-change-btn" onClick={() => setShowPicker(true)}>변경</button>
        )}
      </div>
      <div className="session-desc-banner">{bannerText}</div>
      <div className="page-subtitle">{session.date}</div>
    </div>
  );

  const WorkoutControls = () => (
    <>
      {!workoutRunning && !sessionDone && (
        <button className="btn btn-primary btn-full" style={{marginBottom:12}} onClick={startWorkout}>
          🏋️ 운동 시작
        </button>
      )}
      {workoutRunning && (
        <div style={{display:'flex', gap:8, marginBottom:12}}>
          <div className="workout-elapsed" style={{flex:1}}>⏱ {formatDuration(elapsed)}</div>
          <button className="btn btn-danger" style={{flexShrink:0}} onClick={cancelWorkout}>운동 취소</button>
        </div>
      )}
    </>
  );

  const ExerciseCards = ({ showDifficulty = true }) => (
    <>
      {session.exercises.map((ex, exIdx) => {
        const prevSummary = getPrevSummary(sessionKey, ex.name);
        const hasWeight   = ex.sets.some(s => !s.weightless);
        const exAllDone   = ex.sets.every(s => s.is_completed);
        return (
          <div key={ex.name} className="card exercise-block">
            <div className="exercise-name">
              {ex.name}
              {!exAllDone
                ? <button className="btn btn-ghost" style={{marginLeft:'auto',padding:'4px 10px',fontSize:12}} onClick={() => completeAllSets(exIdx)}>전체 완료</button>
                : <span style={{marginLeft:'auto',color:'var(--green)',fontSize:13}}>✓ 완료</span>
              }
            </div>
            {prevSummary && <div className="prev-record">{prevSummary}</div>}
            <SetHeader hasWeight={hasWeight} />
            {ex.sets.map((set, setIdx) => (
              <SetRow key={setIdx} set={set}
                onChange={(f, v) => updateSet(exIdx, setIdx, f, v)}
                onComplete={() => completeSet(exIdx, setIdx)}
              />
            ))}
            {showDifficulty && !sessionDone && (
              <div className="ex-difficulty-row">
                <span className="difficulty-label">난이도</span>
                {[['high','상 💪'],['mid','중 👊'],['low','하 😌']].map(([val, label]) => (
                  <button key={val}
                    className={`btn difficulty-btn ${ex.difficulty === val ? `active-${val}` : ''}`}
                    onClick={() => setExDifficulty(exIdx, ex.difficulty === val ? null : val)}
                  >{label}</button>
                ))}
              </div>
            )}
          </div>
        );
      })}
    </>
  );

  // ── 러닝 세션 ──
  if (config.type === 'running') {
    return (
      <div className="page">
        {showPicker && <SessionPicker current={sessionKey} onSelect={handlePickSession} onClose={() => setShowPicker(false)} />}
        <Header />
        <WorkoutControls />
        {sessionDone ? (
          <CompleteBanner session={session} nextKey={getNextSession(sessionKey)} onNext={startNextSession} />
        ) : (
          <>
            <RunningTimer onComplete={forceCompleteSession} minutes={config.runMinutes ?? 40}
              memo={session.memo} onMemoChange={v => setSession(s => ({ ...s, memo: v }))} />
            <button className="btn btn-danger btn-full" style={{margin:'8px 0 16px'}} onClick={forceCompleteSession}>
              ⚡ 강제 완료
            </button>
          </>
        )}
      </div>
    );
  }

  // ── 혼합 세션 (운동 + 러닝) ──
  if (config.type === 'mixed') {
    const allExDone = session.exercises.every(ex => ex.sets.every(s => s.is_completed));
    return (
      <div className="page">
        {timer && <RestTimer seconds={timer} onDone={() => setTimer(null)} />}
        {showPicker && <SessionPicker current={sessionKey} onSelect={handlePickSession} onClose={() => setShowPicker(false)} />}
        <Header />
        <WorkoutControls />
        {sessionDone ? (
          <CompleteBanner session={session} nextKey={getNextSession(sessionKey)} onNext={startNextSession} />
        ) : (
          <>
            <ExerciseCards showDifficulty={true} />
            <div className="card" style={{marginTop:8}}>
              <div style={{fontWeight:700, fontSize:15, marginBottom:10}}>🏃 러닝 {config.runMinutes}분</div>
              <RunningTimer onComplete={() => {}} minutes={config.runMinutes}
                memo={session.memo} onMemoChange={v => setSession(s => ({ ...s, memo: v }))} />
            </div>
            <button className="btn btn-danger btn-full" style={{margin:'8px 0 16px'}} onClick={forceCompleteSession}>
              ⚡ 강제 완료
            </button>
            <div style={{display:'flex', gap:8, marginBottom:16}}>
              <button className={`btn ${allExDone ? 'btn-success' : 'btn-ghost'}`} style={{flex:1}} onClick={forceCompleteSession}>
                {allExDone ? '세션 완료 ✓' : '세션 완료'}
              </button>
            </div>
          </>
        )}
      </div>
    );
  }

  // ── 일반 운동 세션 ──
  const allCompleted = session.exercises.every(ex => ex.sets.every(s => s.is_completed));
  return (
    <div className="page">
      {timer && <RestTimer seconds={timer} onDone={() => setTimer(null)} />}
      {showPicker && <SessionPicker current={sessionKey} onSelect={handlePickSession} onClose={() => setShowPicker(false)} />}
      <Header />
      <WorkoutControls />
      {sessionDone && <CompleteBanner session={session} nextKey={getNextSession(sessionKey)} onNext={startNextSession} />}
      <ExerciseCards showDifficulty={true} />
      <div className="card">
        <div style={{marginBottom:8, fontWeight:600}}>메모</div>
        <textarea placeholder="오늘 운동 메모..." value={session.memo}
          onChange={e => setSession(s => { const n={...s,memo:e.target.value}; saveSession(n); return n; })} />
      </div>
      {!sessionDone && (
        <div style={{display:'flex', gap:8, marginBottom:16}}>
          <button className={`btn ${allCompleted ? 'btn-success' : 'btn-ghost'}`} style={{flex:1}} onClick={forceCompleteSession}>
            {allCompleted ? '세션 완료 ✓' : '세션 완료'}
          </button>
          <button className="btn btn-danger" style={{flex:1}} onClick={forceCompleteSession}>⚡ 강제 완료</button>
        </div>
      )}
    </div>
  );
}

function CompleteBanner({ session, nextKey, onNext }) {
  const formatDuration = (s) => { if(!s) return null; const m=Math.floor(s/60),sec=s%60; return sec>0?`${m}분 ${sec}초`:`${m}분`; };
  return (
    <div className="session-banner">
      <h3>세션 완료! 🎉</h3>
      {session.workout_duration && <p>운동 시간: {formatDuration(session.workout_duration)}</p>}
      <p>다음 세션: {nextKey}</p>
      <button className="btn btn-primary btn-full" style={{marginTop:12}} onClick={onNext}>다음 세션 시작</button>
    </div>
  );
}

function SetHeader({ hasWeight }) {
  return (
    <div className="set-header-row">
      <span className="set-label-spacer" />
      {hasWeight ? (
        <>
          <span className="set-col-group">
            <span className="set-col-label prev">지난 무게</span>
            <span className="set-col-label prev">지난 횟수</span>
          </span>
          <span className="set-col-group">
            <span className="set-col-label today">오늘 무게</span>
            <span className="set-col-label today">오늘 횟수</span>
          </span>
        </>
      ) : (
        <>
          <span className="set-col-label prev">지난 횟수</span>
          <span className="set-col-label today">오늘 횟수</span>
        </>
      )}
      <span style={{width:52}} />
    </div>
  );
}

function SetRow({ set, onChange, onComplete }) {
  const labelClass  = set.set_type==='warmup' ? 'warmup' : set.set_type==='cooldown' ? 'cooldown' : 'main';
  const labelText   = set.set_type==='warmup' ? '워밍업' : set.set_type==='cooldown' ? '쿨다운' : `본 ${set.set_number}`;
  const prevW = set.prev_weight, prevR = set.prev_reps;
  const todayW = set.target_weight ?? prevW ?? null;
  const todayR = set.actual_reps   ?? prevR ?? null;

  return (
    <div className={`set-row ${set.is_completed ? 'completed' : ''}`}>
      <span className={`set-label ${labelClass}`}>{labelText}</span>
      {!set.weightless ? (
        <>
          <span className="set-prev-val">{prevW != null ? prevW : '-'}</span>
          <span className="set-prev-val">{prevR != null ? prevR : '-'}</span>
          <input type="number" className="set-today-input" placeholder="-"
            value={todayW ?? ''} min="0" step="2.5"
            onChange={e => onChange('target_weight', e.target.value ? Number(e.target.value) : null)} />
          <input type="number" className="set-today-input" placeholder="-"
            value={todayR ?? ''} min="0"
            onChange={e => onChange('actual_reps', e.target.value ? Number(e.target.value) : null)} />
        </>
      ) : (
        <>
          <span className="set-prev-val">{prevR != null ? prevR : '-'}</span>
          <input type="number" className="set-today-input" placeholder="-"
            value={todayR ?? ''} min="0"
            onChange={e => onChange('actual_reps', e.target.value ? Number(e.target.value) : null)} />
        </>
      )}
      {set.is_pr && <span className="pr-badge">🏆</span>}
      <button className={`check-btn ${set.is_completed ? 'done' : ''}`}
        onClick={onComplete} disabled={set.is_completed}>
        {set.is_completed ? '✓' : '○'}
      </button>
    </div>
  );
}
